using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    // ───────────────────────────────────────────────
    // CreateOrder — Happy Path
    // ───────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_TotalIsSumOfPriceTimesQuantity()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 5.50m, Quantity = 3 },
            new() { ProductName = "Doohickey", Price = 1.25m, Quantity = 4 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        // 10*2 + 5.50*3 + 1.25*4 = 20 + 16.50 + 5 = 41.50
        Assert.AreEqual(41.50m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_OrderHasNonNullIdAndRecentCreatedAt()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);
        var after = DateTime.UtcNow;

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_EachOrderGetsUniqueId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_OrderIsStoredInternally()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-1", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    // ───────────────────────────────────────────────
    // CreateOrder — Error Cases
    // ───────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ───────────────────────────────────────────────
    // CreateOrder — Parameterized Total Calculations
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(1.00, 1, 1.00, DisplayName = "1 × $1.00 = $1.00")]
    [DataRow(7.50, 4, 30.00, DisplayName = "4 × $7.50 = $30.00")]
    [DataRow(0.01, 100, 1.00, DisplayName = "100 × $0.01 = $1.00")]
    [DataRow(99.99, 1, 99.99, DisplayName = "1 × $99.99 = $99.99")]
    public void CreateOrder_VariousPricesAndQuantities_ComputesCorrectTotal(
        double price, int quantity, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    // ───────────────────────────────────────────────
    // GetOrder
    // ───────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsThatOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual(created.CustomerId, result.CustomerId);
        Assert.AreEqual(created.Total, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_MultipleOrders_ReturnsCorrectOne()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-2", items);
        var order3 = _sut.CreateOrder("cust-3", items);

        // Act
        var result = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(order2.Id, result.Id);
        Assert.AreEqual("cust-2", result.CustomerId);
    }

    // ───────────────────────────────────────────────
    // GetOrdersByCustomer
    // ───────────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerHasOrders_ReturnsAllMatchingOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersForCustomer_ReturnsEmptyList()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-unknown");

        // Assert
        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersAtAll_ReturnsEmptyList()
    {
        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-C", items);
        _sut.CreateOrder("cust-B", items);

        // Act
        var resultA = _sut.GetOrdersByCustomer("cust-A");
        var resultB = _sut.GetOrdersByCustomer("cust-B");
        var resultC = _sut.GetOrdersByCustomer("cust-C");

        // Assert
        Assert.AreEqual(2, resultA.Count);
        Assert.AreEqual(2, resultB.Count);
        Assert.AreEqual(1, resultC.Count);
        Assert.IsTrue(resultA.All(o => o.CustomerId == "cust-A"));
        Assert.IsTrue(resultB.All(o => o.CustomerId == "cust-B"));
        Assert.IsTrue(resultC.All(o => o.CustomerId == "cust-C"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsReadOnlyList()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-1", items);

        // Act
        var result = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.IsInstanceOfType<IReadOnlyList<Order>>(result);
    }
}

